const transliterateText = require("./transliterate");

const tests = [
  {
    label: "Telugu -> Gurmukhi",
    text: "\u0C39\u0C48\u0C26\u0C30\u0C3E\u0C2C\u0C3E\u0C26\u0C4D",
    from: "auto",
    to: "gurmukhi"
  },
  {
    label: "Telugu -> Devanagari",
    text: "\u0C39\u0C48\u0C26\u0C30\u0C3E\u0C2C\u0C3E\u0C26\u0C4D",
    from: "auto",
    to: "devanagari"
  },
  {
    label: "Devanagari -> Telugu",
    text: "\u0930\u093E\u092E",
    from: "auto",
    to: "telugu"
  },
  {
    label: "Gurmukhi -> Telugu",
    text: "\u0A38\u0A24\u0A3F \u0A38\u0A3C\u0A4D\u0A30\u0A40 \u0A05\u0A15\u0A3E\u0A32",
    from: "auto",
    to: "telugu"
  },
  {
    label: "Roman ITRANS -> Malayalam",
    text: "namaste",
    from: "itrans",
    to: "malayalam"
  }
];

for (const test of tests) {
  try {
    const result = transliterateText(test.text, test.from, test.to);
    console.log("----");
    console.log(test.label);
    console.log(result);
  } catch (error) {
    console.log("----");
    console.log(test.label);
    console.error("Error:", error.message);
  }
}